import subprocess
import hashlib
import os

def generate_requirements():
    # First, generating a clean requirements.txt file using pip freeze
    print("Generating requirements.txt file...")
    subprocess.run(["pip", "freeze", ">", "requirements.txt"])

def add_hashes_req():
    
    print("Adding hashes to requirements.txt file...")
    # Open the requirements file
    with open('requirements.txt', 'r+') as file:
        lines = file.readlines()
        file.seek(0)
        file.truncate()
        # Go through each line (each package) and add the hash
        for line in lines:
            package_name = line.split('==')[0]
            package_version = line.split('==')[1].strip()

            # Getting the package file name
            package_file = f'{package_name.replace("-", "_").replace(".", "_")}-{package_version}-py3-none-any.whl'

            # Downloading the package
            os.system(f'pip download {package_name}=={package_version}')

            # Calculating the SHA256 hash of the package
            with open(package_file, 'rb') as package:
                bytes = package.read()
                readable_hash = hashlib.sha256(bytes).hexdigest()

            # Write the package to the requirements file with its hash
            file.write(f'{package_name}=={package_version} --hash=sha256:{readable_hash}\n')

            # Removing the downloaded package file
            os.remove(package_file)

generate_requirements()
add_hashes_req()